template.script:
            //
(function () {
    'use strict';

    /* Guard: only initialise once per page load */
    if (window.__portalMobileNavInit) return;
    window.__portalMobileNavInit = true;

    document.addEventListener('DOMContentLoaded', function () {

        var hamburgerBtn = document.getElementById('portalHamburgerBtn');
        var drawerClose  = document.getElementById('portalDrawerClose');
        var overlay      = document.getElementById('portalNavOverlay');
        var drawer       = document.getElementById('portalNavDrawer');

        if (!drawer) return; // component not present on this page

        // ── OPEN / CLOSE HELPERS ──────────────────────────────────────
        function openDrawer() {
            drawer.classList.add('open');
            overlay.classList.add('open');
            document.body.style.overflow = 'hidden';
            if (hamburgerBtn) hamburgerBtn.setAttribute('aria-expanded', 'true');
        }

        function closeDrawer() {
            drawer.classList.remove('open');
            overlay.classList.remove('open');
            document.body.style.overflow = '';
            if (hamburgerBtn) hamburgerBtn.setAttribute('aria-expanded', 'false');
        }

        // ── TRIGGERS ─────────────────────────────────────────────────
        if (hamburgerBtn) hamburgerBtn.addEventListener('click', openDrawer);
        if (drawerClose)  drawerClose.addEventListener('click', closeDrawer);
        if (overlay)      overlay.addEventListener('click', closeDrawer);

        // ESC key closes drawer
        document.addEventListener('keydown', function (e) {
            if (e.key === 'Escape') closeDrawer();
        });

        // Swipe-left to close on touch devices
        var touchStartX = 0;
        drawer.addEventListener('touchstart', function (e) {
            touchStartX = e.touches[0].clientX;
        }, { passive: true });
        drawer.addEventListener('touchend', function (e) {
            if (touchStartX - e.changedTouches[0].clientX > 60) closeDrawer();
        }, { passive: true });

        // ── DRAWER NAV LINK WIRING ────────────────────────────────────

        function setDrawerActive(el) {
            drawer.querySelectorAll('.portal-nav-item').forEach(function (item) {
                item.classList.remove('active');
            });
            if (el) el.classList.add('active');
        }

        // Overview — delegates to header nav click (handles SPA page switch)
        var drawerOverview = document.getElementById('drawerOverviewLink');
        if (drawerOverview) {
            drawerOverview.addEventListener('click', function (e) {
                e.preventDefault();
                closeDrawer();
                var nav = document.getElementById('portalOverviewNav');
                if (nav) nav.click(); else window.location.href = '/customer_support/dashboard';
                setDrawerActive(this);
            });
        }

        // Reporting — delegates to header nav click
        var drawerReporting = document.getElementById('drawerReportingLink');
        if (drawerReporting) {
            drawerReporting.addEventListener('click', function (e) {
                e.preventDefault();
                closeDrawer();
                var nav = document.getElementById('portalReportingNav');
                if (nav) nav.click(); else window.location.href = '/customer_support/dashboard#reporting';
                setDrawerActive(this);
            });
        }

        // Tickets — has a real href; just close drawer and let browser navigate
        var drawerTickets = document.getElementById('drawerTicketsLink');
        if (drawerTickets) {
            drawerTickets.addEventListener('click', function () {
                closeDrawer();
                // navigation happens via href
            });
        }

        // ── SYNC DRAWER ACTIVE STATE WITH HEADER NAV ──────────────────
        // Runs once on load so the drawer highlights the correct item
        // even on pages that don't call showOverview() / showReporting().
        var activeHeaderNav = document.querySelector('.header-nav .nav-link.active');
        if (activeHeaderNav) {
            var idMap = {
                'portalOverviewNav':  'drawerOverviewLink',
                'portalReportingNav': 'drawerReportingLink',
                'portalTicketsNav':   'drawerTicketsLink'
            };
            var drawerId = idMap[activeHeaderNav.id];
            if (drawerId) setDrawerActive(document.getElementById(drawerId));
        }

    }); // DOMContentLoaded

})();
            //
